operations.new:
function beep(type) {
  if (!state.soundEnabled) {
    return;
  }
  const ctx = initAudio();
  if (!ctx) {
    return;
  }

  const patterns = {
    success: [
      { frequency: 860, duration: 0.22, wave: "sine" },
      { frequency: 1180, duration: 0.28, wave: "sine" }
    ],
    error: [
      { frequency: 280, duration: 0.22, wave: "square" },
      { frequency: 205, duration: 0.24, wave: "square" },
      { frequency: 150, duration: 0.22, wave: "square" }
    ],
    complete: [
      { frequency: 660, duration: 0.22, wave: "triangle" },
      { frequency: 880, duration: 0.22, wave: "triangle" },
      { frequency: 1320, duration: 0.30, wave: "triangle" }
    ]
  };

  let cursor = ctx.currentTime;
  const sequence = patterns[type] || patterns.error;
  sequence.forEach((step) => {
    const oscillator = ctx.createOscillator();
    const gain = ctx.createGain();
    oscillator.connect(gain);
    gain.connect(ctx.destination);
    oscillator.type = step.wave;
    oscillator.frequency.setValueAtTime(step.frequency, cursor);
    gain.gain.setValueAtTime(0.0001, cursor);
    gain.gain.exponentialRampToValueAtTime(type === "error" ? 0.18 : 0.16, cursor + 0.025);
    gain.gain.exponentialRampToValueAtTime(0.0001, cursor + step.duration);
    oscillator.start(cursor);
    oscillator.stop(cursor + step.duration + 0.02);
    cursor += step.duration + 0.035;
  });
}

