operations.new:
function updateWorkflowManualPalletModeUi() {
  workflowManualPalletToggle.checked = Boolean(state.manualPalletEntry);
  workflowNextPalletSubmitBtn.classList.toggle("hidden", !state.manualPalletEntry);
}

function showWorkflowModal(type, title, message, kicker) {
  const isCompletionModal = type === "success" && title === "Pallet completed correctly";
  workflowModalCard.className = "workflow-modal-card " + type;
  workflowModalKicker.textContent = kicker || "Workflow Message";
  workflowModalTitle.textContent = title;
  workflowModalMessage.textContent = message;
  workflowNextPalletPanel.classList.toggle("hidden", !isCompletionModal);
  if (isCompletionModal) {
    workflowNextPalletInput.value = "";
    updateWorkflowManualPalletModeUi();
  }
  workflowModal.classList.add("active");
  if (isCompletionModal) {
    setTimeout(() => {
      workflowNextPalletInput.focus();
      workflowNextPalletInput.select();
    }, 60);
  }
}

function hideWorkflowModal() {
  workflowModal.classList.remove("active");
  workflowNextPalletPanel.classList.add("hidden");
  workflowNextPalletInput.value = "";
}

