function searchPalletFromWorkflowModal() {
  const nextPalletId = normalize(workflowNextPalletInput.value);
  if (!nextPalletId) {
    workflowNextPalletInput.focus();
    return;
  }
  palletSearchInput.value = nextPalletId;
  workflowNextPalletInput.value = "";
  searchPallet();
}

