workflowManualPalletToggle.addEventListener("change", () => {
  state.manualPalletEntry = workflowManualPalletToggle.checked;
  clearTimeout(palletAutoSubmitTimer);
  saveState();
  updateManualPalletModeUi();
  updateWorkflowManualPalletModeUi();
  workflowNextPalletInput.focus();
});
workflowNextPalletSubmitBtn.addEventListener("click", () => {
  clearTimeout(palletAutoSubmitTimer);
  searchPalletFromWorkflowModal();
});
workflowNextPalletInput.addEventListener("keydown", (event) => {
  if (event.key === "Enter") {
    event.preventDefault();
    clearTimeout(palletAutoSubmitTimer);
    if (!state.manualPalletEntry) {
      searchPalletFromWorkflowModal();
    }
  }
});
workflowNextPalletInput.addEventListener("input", () => {
  if (state.manualPalletEntry) {
    return;
  }
  clearTimeout(palletAutoSubmitTimer);
  palletAutoSubmitTimer = setTimeout(() => {
    if (normalize(workflowNextPalletInput.value)) {
      searchPalletFromWorkflowModal();
    }
  }, 140);
});
